export type FontSize = 'sm' | 'md' | 'lg';
export type BrowsingMode = 'full' | 'page';
export type FontStyleType = 'standard' | 'scheherazade';
export type ViewMode = 'mushaf' | 'reading' | 'study';

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import type { SurahData, Ayah, SavedItem, ViewMode } from './types';
import { useQuranData } from './hooks/useQuranData';
import { useSettings } from './hooks/useSettings';
import { useRouting } from './hooks/useRouting';
import { useAudioPlayer } from './hooks/useAudioPlayer';
import { useNotebook } from './hooks/useNotebook';
import { AuthProvider } from './hooks/useAuth';
import { useSearch } from './hooks/useSearch';
import { useServiceWorkerUpdater } from './hooks/useServiceWorkerUpdater';
import AppRouter from './components/AppRouter';
import TopProgressBar from './components/TopProgressBar';
import SidePanel from './components/SidePanel';
import AudioPlayerBar from './components/AudioPlayerBar';
import Toolbox from './components/Toolbox';
import SaveItemModal from './components/SaveItemModal';
import UpdateNotification from './components/UpdateNotification';
import { ArrowUpIcon } from './components/icons';
import Header from './components/Header';


const KHATMIYAH_AUDIO_PROGRESS_KEY = 'qran_khatmiyah_audio_progress';


const App: React.FC = () => {
    // --- State from Hooks ---
    const {
        allQuranData, isInitialLoading, isBackgroundLoading, loadingEditions,
        fetchCustomEditionData, dataSourceStatus
    } = useQuranData();

    const { currentPath, pathParts, queryParams } = useRouting();

    const {
        fontSize, setFontSize,
        browsingMode, setBrowsingMode, activeEditions, selectedEdition,
        setSelectedEdition, selectedAudioEdition, setSelectedAudioEdition,
        displayEdition, fontStyle, setFontStyle
    } = useSettings();

    const { 
        simpleSearchableAyahs, 
        tryParseAyahReference, 
        performSearch, 
        performSearchByAyahNumber 
    } = useSearch(allQuranData);

    const {
        playbackInfo, currentlyPlayingAyahGlobalNumber, selectedAudioEditionDetails,
        handleStartPlayback, handlePlayPause, handleNext, handlePrev, handleClosePlayback, ALL_AUDIO_EDITIONS
    } = useAudioPlayer(currentPath, allQuranData, selectedAudioEdition, setSelectedAudioEdition, fetchCustomEditionData);

    const {
        collections, itemToSave, setItemToSave, handleSaveItem, handleConfirmSave,
        handleDeleteCollection, handleDeleteSavedItem, handleExportNotebook,
        handleImportNotebook, updateItemNotes,
    } = useNotebook();

    const { showUpdateNotification, handleUpdate } = useServiceWorkerUpdater();

    // --- App-level State ---
    const [viewMode, setViewMode] = useState<ViewMode>('mushaf');
    const [isSearching, setIsSearching] = useState<boolean>(false);
    const [showScroll, setShowScroll] = useState(false);
    const [isSidePanelOpen, setIsSidePanelOpen] = useState(false);

    const [audioKhatmiyahProgress, setAudioKhatmiyahProgress] = useState<{ ayahNumber: number } | null>(() => {
        try {
            const stored = localStorage.getItem(KHATMIYAH_AUDIO_PROGRESS_KEY);
            if (stored) return JSON.parse(stored);
        } catch (e) { console.error("Failed to parse audio khatmiyah progress", e); }
        return { ayahNumber: 1 };
    });

    // Sync viewMode with underlying browsingMode and selectedEdition
    useEffect(() => {
        switch (viewMode) {
            case 'mushaf':
                setBrowsingMode('page');
                setSelectedEdition('quran-uthmani-quran-academy');
                break;
            case 'reading':
                setBrowsingMode('full');
                setSelectedEdition('quran-uthmani-quran-academy');
                break;
            case 'study':
                setBrowsingMode('full');
                setSelectedEdition('quran-simple-clean');
                break;
        }
    }, [viewMode, setBrowsingMode, setSelectedEdition]);

    // Sync viewMode FROM underlying states on initial load or external changes
    useEffect(() => {
        if (browsingMode === 'page' && selectedEdition.includes('uthmani')) {
            setViewMode('mushaf');
        } else if (browsingMode === 'full' && selectedEdition.includes('uthmani')) {
            setViewMode('reading');
        } else if (browsingMode === 'full' && selectedEdition.includes('simple')) {
            setViewMode('study');
        }
    }, [browsingMode, selectedEdition]);


    const handleSaveAudioKhatmiyahProgress = useCallback((ayahNumber: number) => {
        const newProgress = { ayahNumber };
        setAudioKhatmiyahProgress(newProgress);
        localStorage.setItem(KHATMIYAH_AUDIO_PROGRESS_KEY, JSON.stringify(newProgress));
    }, []);

    // --- UI Effects ---
    useEffect(() => {
        const checkScrollTop = () => setShowScroll(window.pageYOffset > 400);
        window.addEventListener('scroll', checkScrollTop);
        return () => window.removeEventListener('scroll', checkScrollTop);
    }, []);

    useEffect(() => {
        if (!isInitialLoading) {
            const loader = document.querySelector('.static-loader');
            if (loader) {
                (loader as HTMLElement).style.opacity = '0';
                setTimeout(() => loader.remove(), 500);
            }
        }
    }, [isInitialLoading]);

    // --- Search Handlers ---
    const handleSearch = (query: string, sourceEdition?: string, position?: { surah: number; ayah: number; wordIndex: number; }) => {
        const ayahRef = tryParseAyahReference(query);
        if (ayahRef && !position) {
            window.location.hash = `#/surah/${ayahRef.surah}?ayah=${ayahRef.ayah}`;
            return;
        }
        setIsSearching(true);
        let url = `#/search/${encodeURIComponent(query)}?search_edition=${sourceEdition || 'quran-simple-clean'}`;
        if (position) url += `&s=${position.surah}&a=${position.ayah}&w=${position.wordIndex}`;
        window.location.hash = url;
    };

    const handleSearchByAyahNumber = (ayahNumber: number) => {
        setIsSearching(true);
        window.location.hash = `#/search/number/${ayahNumber}`;
    };


    // --- Other Handlers ---
    const scrollToTop = () => window.scrollTo({ top: 0, behavior: 'smooth' });

    // --- Data Derivations for Views ---
    const quranData = useMemo(() => allQuranData?.[selectedEdition], [allQuranData, selectedEdition]);

    const hizbQuarterStartMap = useMemo(() => {
        if (!simpleSearchableAyahs) return new Map<number, number>();
        const map = new Map<number, number>();
        simpleSearchableAyahs.forEach(ayah => {
            if (ayah.hizbQuarter && !map.has(ayah.hizbQuarter)) {
                map.set(ayah.hizbQuarter, ayah.number);
            }
        });
        return map;
    }, [simpleSearchableAyahs]);

    const isAudioKhatmiyahPage = currentPath.startsWith('#/audio-khatmiyah');
    const isPageWithToolbox = useMemo(() => 
        (currentPath.startsWith('#/surah/') || currentPath.startsWith('#/search/') || currentPath.startsWith('#/page/')) && !isAudioKhatmiyahPage, 
    [currentPath, isAudioKhatmiyahPage]);

    return (
        <AuthProvider>
            <div className="bg-background text-text-primary min-h-screen transition-colors duration-300">
                <TopProgressBar isSearching={isSearching || isBackgroundLoading || loadingEditions.length > 0} />
                <SidePanel 
                    isOpen={isSidePanelOpen}
                    onClose={() => setIsSidePanelOpen(false)}
                    currentPath={currentPath}
                    onNavigate={(path) => {
                        const currentHash = window.location.hash || '#/';
                        if (currentHash !== path) {
                            window.location.hash = path;
                        }
                        setIsSidePanelOpen(false);
                    }}
                />
                {!isAudioKhatmiyahPage && (
                    <Header
                        setIsSidePanelOpen={setIsSidePanelOpen}
                        currentPath={currentPath}
                        dataSourceStatus={dataSourceStatus}
                        onSearch={handleSearch}
                        isInitialLoading={isInitialLoading}
                        viewMode={viewMode}
                        onViewModeChange={setViewMode}
                        onStartPlayback={handleStartPlayback}
                        isPlaybackLoading={!!playbackInfo?.trigger}
                        selectedAudioEdition={selectedAudioEdition}
                    />
                )}
                <main className={`pt-8 pb-24 ${isAudioKhatmiyahPage ? 'pt-0' : ''}`}>
                    <AppRouter
                        pathParts={pathParts}
                        queryParams={queryParams}
                        isInitialLoading={isInitialLoading}
                        quranData={quranData}
                        simpleSearchableAyahs={simpleSearchableAyahs}
                        collections={collections}
                        audioKhatmiyahProgress={audioKhatmiyahProgress}
                        handleSaveAudioKhatmiyahProgress={handleSaveAudioKhatmiyahProgress}
                        ALL_AUDIO_EDITIONS={ALL_AUDIO_EDITIONS}
                        selectedAudioEdition={selectedAudioEdition}
                        setSelectedAudioEdition={setSelectedAudioEdition}
                        allQuranData={allQuranData}
                        fetchCustomEditionData={fetchCustomEditionData}
                        fontSize={fontSize}
                        setFontSize={setFontSize}
                        activeEditions={activeEditions}
                        selectedEdition={selectedEdition}
                        setSelectedEdition={setSelectedEdition}
                        handleDeleteCollection={handleDeleteCollection}
                        handleDeleteSavedItem={handleDeleteSavedItem}
                        updateItemNotes={updateItemNotes}
                        handleExportNotebook={handleExportNotebook}
                        handleImportNotebook={handleImportNotebook}
                        handleSearch={handleSearch}
                        displayEdition={displayEdition}
                        browsingMode={browsingMode}
                        fontStyle={fontStyle}
                        handleSaveItem={handleSaveItem as (item: SavedItem) => void}
                        handleSearchByAyahNumber={handleSearchByAyahNumber}
                        currentlyPlayingAyahGlobalNumber={currentlyPlayingAyahGlobalNumber}
                        playbackInfo={playbackInfo}
                        handleStartPlayback={handleStartPlayback as (ayahs: Ayah[], audioEditionIdentifier: string, startIndex?: number) => void}
                        hizbQuarterStartMap={hizbQuarterStartMap}
                        setIsSearching={setIsSearching}
                        performSearchByAyahNumber={performSearchByAyahNumber}
                        performSearch={performSearch}
                    />
                </main>

                {isPageWithToolbox && <Toolbox
                    fontSize={fontSize} onFontSizeChange={setFontSize}
                    isAudioPlayerVisible={!!playbackInfo}
                />}
                {itemToSave && <SaveItemModal item={itemToSave} collections={collections} onClose={() => setItemToSave(null)} onSave={handleConfirmSave} />}
                {playbackInfo && !isAudioKhatmiyahPage && <AudioPlayerBar 
                    playlist={playbackInfo.playlist} currentIndex={playbackInfo.currentIndex}
                    isPlaying={playbackInfo.isPlaying} isLoading={!!playbackInfo?.trigger}
                    onPlayPause={handlePlayPause} onNext={handleNext} onPrev={handlePrev}
                    onEnded={handleNext} onClose={handleClosePlayback}
                    audioEdition={selectedAudioEditionDetails}
                />}
                {showScroll && !isAudioKhatmiyahPage && <button onClick={scrollToTop} className={`fixed left-8 p-4 bg-primary text-white rounded-full shadow-lg hover:bg-primary-hover transition-all duration-300 focus:outline-none focus:ring-2 focus:ring-primary focus:ring-opacity-50 ${!!playbackInfo ? 'bottom-28' : 'bottom-8'}`} aria-label="الانتقال إلى الأعلى"><ArrowUpIcon className="w-6 h-6" /></button>}
                {showUpdateNotification && <UpdateNotification onUpdate={handleUpdate} />}
            </div>
        </AuthProvider>
    );
};

export default App;

import React, { useState, useMemo, useCallback } from 'react';
import { MenuIcon, LogoIcon, SearchIcon, ArrowRightIcon, PlayIcon, SpinnerIcon } from './icons';
import { QURAN_INDEX } from '../quranIndex';
import { formatSurahNameForDisplay } from '../utils/text';
import SearchForm from './SearchForm';
import ThemeToggleButton from './ThemeToggleButton';
import type { Ayah, ViewMode } from '../types';
import ViewModeControl from './ViewModeControl';

interface HeaderProps {
    setIsSidePanelOpen: (open: boolean) => void;
    currentPath: string;
    dataSourceStatus: 'primary' | 'fallback';
    onSearch: (query: string) => void;
    isInitialLoading: boolean;
    viewMode: ViewMode;
    onViewModeChange: (mode: ViewMode) => void;
    onStartPlayback: (ayahs: Ayah[], audioEditionIdentifier: string, startIndex?: number) => void;
    isPlaybackLoading: boolean;
    selectedAudioEdition: string;
}

const Logo: React.FC<{ dataSourceStatus: 'primary' | 'fallback'; isHomePage: boolean }> = ({ dataSourceStatus, isHomePage }) => {
    const [adminClickCount, setAdminClickCount] = useState(0);

    const handleLogoClick = () => {
        const newCount = adminClickCount + 1;
        setAdminClickCount(newCount);
        if (newCount >= 12) {
            window.location.hash = '#/admin';
            setAdminClickCount(0);
            return;
        }

        window.location.hash = '#/';
    };

    const dotColorClass = dataSourceStatus === 'primary' ? 'text-green-500' : 'text-red-500';

    return (
        <div onClick={handleLogoClick} className="flex items-center gap-2 cursor-pointer select-none" title="الرجوع للرئيسية">
            <LogoIcon className="w-7 h-7 text-primary" />
            <span className="text-xl font-bold text-text-primary tracking-tighter">
                QRAN<span className={dotColorClass}>.</span>TOP
            </span>
        </div>
    );
};

const Header: React.FC<HeaderProps> = ({
    setIsSidePanelOpen,
    currentPath,
    dataSourceStatus,
    onSearch,
    isInitialLoading,
    viewMode,
    onViewModeChange,
    onStartPlayback,
    isPlaybackLoading,
    selectedAudioEdition,
}) => {
    const [isMobileSearchOpen, setIsMobileSearchOpen] = useState(false);

    const { pageTitle, isSurahOrPage, isRelevantPageForToggle, isSearchPage, isHomePage } = useMemo(() => {
        const path = currentPath.split('?')[0];
        const isHome = path === '#/';
        const isSearch = path.startsWith('#/search/');
        const isSurah = path.startsWith('#/surah/');
        const isPage = path.startsWith('#/page/');
        const isRelevant = isSurah || isPage || isSearch;

        let title = "QRAN.TOP";
        if (!isHome) {
            if (isSurah) {
                const surahNum = parseInt(path.split('/')[2], 10);
                const surah = QURAN_INDEX.find(s => s.number === surahNum);
                if (surah) title = formatSurahNameForDisplay(surah.name);
            } else if (isPage) {
                const pageNum = path.split('/')[2];
                title = `الصفحة ${pageNum}`;
            } else if (isSearch) {
                title = "نتائج البحث";
            }
        } else {
            title = "الفهرس";
        }

        return { 
            pageTitle: title, 
            isSurahOrPage: isSurah || isPage, 
            isRelevantPageForToggle: isRelevant,
            isSearchPage: isSearch,
            isHomePage: isHome
        };
    }, [currentPath]);

    const handlePlaySurah = useCallback(() => {
        onStartPlayback([], selectedAudioEdition);
    }, [onStartPlayback, selectedAudioEdition]);

    const handleSearchSubmit = (query: string) => {
        onSearch(query);
        setIsMobileSearchOpen(false);
    };

    return (
        <header className="sticky top-0 z-30 bg-surface/90 backdrop-blur-md shadow-sm border-b border-border-default transition-all duration-300">
            <div className="w-full max-w-7xl mx-auto px-4">
                <div className="flex items-center justify-between h-16 gap-2">

                    {isMobileSearchOpen ? (
                        <div className="flex items-center w-full gap-2 animate-fade-in">
                            <button onClick={() => setIsMobileSearchOpen(false)} className="p-2 text-text-secondary hover:bg-surface-hover rounded-full">
                                <ArrowRightIcon className="w-6 h-6" />
                            </button>
                            <div className="flex-grow">
                                <SearchForm onSearch={handleSearchSubmit} disabled={isInitialLoading} />
                            </div>
                        </div>
                    ) : (
                        <>
                            <div className="flex items-center gap-1 sm:gap-2 flex-shrink-0">
                                <button
                                    onClick={() => setIsSidePanelOpen(true)}
                                    className="p-2 text-text-muted rounded-full hover:bg-surface-hover transition-colors"
                                    aria-label="فتح القائمة"
                                >
                                    <MenuIcon className="w-6 h-6" />
                                </button>
                                <ThemeToggleButton />
                            </div>

                            <div className="flex-grow flex justify-center min-w-0 px-2">
                                <div className="md:hidden text-lg font-bold text-text-primary truncate" title={pageTitle}>
                                    {pageTitle}
                                </div>

                                <div className="hidden md:block w-full max-w-xl">
                                    {isSearchPage || isSurahOrPage ? (
                                        <ViewModeControl activeMode={viewMode} onModeChange={onViewModeChange} />
                                    ) : (
                                        <SearchForm onSearch={onSearch} disabled={isInitialLoading} />
                                    )}
                                </div>
                            </div>

                            <div className="flex items-center gap-2 sm:gap-3 flex-shrink-0">
                                {isSurahOrPage && (
                                    <button
                                        onClick={handlePlaySurah}
                                        disabled={isPlaybackLoading}
                                        className="hidden md:flex p-2 bg-primary text-white rounded-full shadow-md hover:bg-primary-hover transition-colors disabled:opacity-60"
                                        aria-label="استماع"
                                    >
                                        {isPlaybackLoading ? <SpinnerIcon className="w-4 h-4"/> : <PlayIcon className="w-4 h-4"/>}
                                    </button>
                                )}

                                {!isSearchPage && !isSurahOrPage && (
                                    <button 
                                        onClick={() => setIsMobileSearchOpen(true)}
                                        className="md:hidden p-2 text-text-muted hover:text-primary hover:bg-surface-hover rounded-full"
                                        aria-label="بحث"
                                    >
                                        <SearchIcon className="w-6 h-6" />
                                    </button>
                                )}

                                <div className="w-px h-6 bg-border-default mx-1"></div>

                                <Logo dataSourceStatus={dataSourceStatus} isHomePage={isHomePage} />
                            </div>
                        </>
                    )}
                </div>
            </div>
        </header>
    );
};

export default Header;

import React, { useState, useEffect, useRef } from 'react';
import type { QuranFont, QuranEdition, FontSize, BrowsingMode } from '../types';
import { ArrowLeftIcon, ArrowRightIcon, HomeIcon, TextSizeIcon, PlusIcon, MinusIcon, SparklesIcon, BookOpenIcon, CheckIcon, DocumentDuplicateIcon, QueueListIcon } from './icons';

interface ToolboxProps {
    // Font Size
    fontSize: FontSize;
    onFontSizeChange: (size: FontSize) => void;
    isAudioPlayerVisible: boolean;
}

const Toolbox: React.FC<ToolboxProps> = ({
    fontSize, onFontSizeChange,
    isAudioPlayerVisible
}) => {
    type Popover = 'size';
    const [openPopover, setOpenPopover] = useState<Popover | null>(null);
    const [isShown, setIsShown] = useState(true);
    const popoverRef = useRef<HTMLDivElement>(null);
    const lastScrollY = useRef(0);

    // Effect to handle toolbox visibility on scroll
    useEffect(() => {
        const handleScroll = () => {
            const currentScrollY = window.scrollY;
            const scrollThreshold = 20;

            // Do nothing if scroll change is insignificant
            if (Math.abs(currentScrollY - lastScrollY.current) < scrollThreshold) {
                return;
            }

            if (currentScrollY < 100) { // Always show near the top
                setIsShown(true);
            } else if (currentScrollY > lastScrollY.current) { // Scrolling down
                setIsShown(false);
                setOpenPopover(null); // Hide popovers when toolbar hides
            } else { // Scrolling up
                setIsShown(true);
            }
            lastScrollY.current = currentScrollY;
        };

        window.addEventListener('scroll', handleScroll, { passive: true });
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    // Close popover on outside click
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (popoverRef.current && !popoverRef.current.contains(event.target as Node)) {
                setOpenPopover(null);
            }
        };
        if (openPopover) {
            document.addEventListener('mousedown', handleClickOutside);
        }
        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, [openPopover]);

    const handleTogglePopover = (popover: Popover) => {
        setOpenPopover(prev => (prev === popover ? null : popover));
    };

    const ToolButton: React.FC<{ onClick: () => void; label: string; children: React.ReactNode; isActive?: boolean }> = ({ onClick, label, children, isActive }) => (
        <button
            onClick={onClick}
            aria-label={label}
            title={label}
            className={`p-3 rounded-full transition-colors ${isActive ? 'bg-surface-active text-primary-text-strong' : 'text-text-muted hover:bg-surface-hover'}`}
        >
            {children}
        </button>
    );

    const PopoverContainer: React.FC<{ children: React.ReactNode; popoverId: Popover, title: string, widthClass?: string }> = ({ children, popoverId, title, widthClass = 'w-72' }) => (
        openPopover === popoverId ? (
            <div ref={popoverRef} className={`absolute bottom-full left-1/2 -translate-x-1/2 mb-3 ${widthClass} bg-surface rounded-lg shadow-2xl ring-1 ring-black/5 animate-fade-in`}
                role="dialog" aria-labelledby={`${popoverId}-title`}>
                <div className="p-3 border-b border-border-default">
                    <h3 id={`${popoverId}-title`} className="font-semibold text-text-primary">{title}</h3>
                </div>
                <div className="p-3 max-h-64 overflow-y-auto">
                    {children}
                </div>
                <div className={`absolute left-1/2 -translate-x-1/2 bottom-[-8px] w-4 h-4 bg-surface rotate-45 -z-10`}></div>
            </div>
        ) : null
    );

    return (
        <div className={`fixed left-1/2 -translate-x-1/2 z-20 transition-all duration-300 ${isAudioPlayerVisible ? 'bottom-28' : 'bottom-8'}`}>
            <div className={`relative flex items-center gap-1 bg-surface/80 backdrop-blur-md p-2 rounded-full shadow-lg border border-border-default transition-all duration-300 ${
                isShown ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-16 pointer-events-none'
            }`}>

                {/* Navigation Group */}
                <ToolButton onClick={() => window.history.back()} label="الخلف"><ArrowRightIcon className="w-5 h-5" /></ToolButton>
                <ToolButton onClick={() => window.location.hash = '#/'} label="الرئيسية"><HomeIcon className="w-5 h-5" /></ToolButton>
                <ToolButton onClick={() => window.history.forward()} label="الأمام"><ArrowLeftIcon className="w-5 h-5" /></ToolButton>

                <div className="h-6 w-px bg-border-default mx-2"></div>

                {/* Settings Group */}
                <div className="relative">
                    <ToolButton onClick={() => handleTogglePopover('size')} label="حجم الخط" isActive={openPopover === 'size'}>
                        <TextSizeIcon className="w-5 h-5" />
                    </ToolButton>
                    <PopoverContainer popoverId="size" title="تغيير حجم الخط" widthClass="w-auto">
                        <div className="flex items-center justify-center gap-2">
                            <button
                                onClick={() => onFontSizeChange('sm')}
                                className={`p-3 w-16 h-12 flex items-center justify-center rounded-lg transition-colors ${fontSize === 'sm' ? 'bg-surface-active text-primary-text-strong' : 'bg-surface-subtle hover:bg-surface-hover'}`}
                                aria-pressed={fontSize === 'sm'}
                                title="صغير"
                            >
                                <span className="text-sm font-bold">A</span>
                            </button>
                            <button
                                onClick={() => onFontSizeChange('md')}
                                className={`p-3 w-16 h-12 flex items-center justify-center rounded-lg transition-colors ${fontSize === 'md' ? 'bg-surface-active text-primary-text-strong' : 'bg-surface-subtle hover:bg-surface-hover'}`}
                                aria-pressed={fontSize === 'md'}
                                title="متوسط"
                            >
                                <span className="text-lg font-bold">A</span>
                            </button>
                            <button
                                onClick={() => onFontSizeChange('lg')}
                                className={`p-3 w-16 h-12 flex items-center justify-center rounded-lg transition-colors ${fontSize === 'lg' ? 'bg-surface-active text-primary-text-strong' : 'bg-surface-subtle hover:bg-surface-hover'}`}
                                aria-pressed={fontSize === 'lg'}
                                title="كبير"
                            >
                                <span className="text-xl font-bold">A</span>
                            </button>
                        </div>
                    </PopoverContainer>
                </div>
            </div>
        </div>
    );
};

export default Toolbox;

import React from 'react';
import type { ViewMode } from '../types';
import { BookOpenIcon, QueueListIcon, SparklesIcon } from './icons';

interface ViewModeControlProps {
    activeMode: ViewMode;
    onModeChange: (mode: ViewMode) => void;
}

const ViewModeControl: React.FC<ViewModeControlProps> = ({ activeMode, onModeChange }) => {
    const modes: { id: ViewMode; label: string; icon: React.ReactNode }[] = [
        { id: 'mushaf', label: 'مصحف', icon: <BookOpenIcon className="w-4 h-4" /> },
        { id: 'reading', label: 'قراءة', icon: <QueueListIcon className="w-4 h-4" /> },
        { id: 'study', label: 'تدبر', icon: <SparklesIcon className="w-4 h-4" /> },
    ];

    return (
        <div className="flex items-center bg-surface-subtle p-1 rounded-full border border-border-default shadow-sm">
            {modes.map(mode => (
                <button
                    key={mode.id}
                    onClick={() => onModeChange(mode.id)}
                    className={`flex items-center justify-center gap-2 w-full px-3 py-1.5 rounded-full text-sm font-semibold transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-primary focus:ring-opacity-50 ${
                        activeMode === mode.id
